import React from 'react';

interface OmegaMessageProps {
  role: 'user' | 'assistant';
  content: string;
  timestamp?: string;
  onCopy?: (text: string) => void;
}

export function OmegaMessage({
  role,
  content,
  timestamp,
  onCopy,
}: OmegaMessageProps) {
  const isUser = role === 'user';
  const isAssistant = role === 'assistant';

  const handleCopy = () => {
