          {content}
        </div>
        {isAssistant && (
          <div className='flex gap-2 mt-2 pt-2 border-t border-gray-300'>
            <button
              onClick={handleCopy}
              className='text-xs px-2 py-1 hover:bg-gray-300 rounded'
              title='Copy message'
