'use client';

import React, { useState } from 'react';

interface ChatComposerProps {
  onSendMessage: (text: string) => void;
  onVoiceStart?: () => void;
  isStreaming?: boolean;
  isVoiceActive?: boolean;
  heardText?: string;
}

export function ChatComposer({
  onSendMessage,
  onVoiceStart,
  isStreaming = false,
  isVoiceActive = false,
  heardText = '',
}: ChatComposerProps) {
  const [text, setText] = useState('');

  const handleSend = () => {
    if (text.trim()) {
      onSendMessage(text);
      setText('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className='border-t border-gray-200 bg-white p-4'>
      {heardText && (
        <div className='mb-2 text-sm italic text-gray-600'>
          <span className='font-semibold'>Heard:</span> {heardText}
        </div>
      )}

      <div className='flex gap-2'>
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder='Type a message... (Shift+Enter for newline)'
          disabled={isStreaming}
          className='flex-1 resize-none border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100'
          rows={3}
        />

        <div className='flex flex-col gap-2'>
          <button
            onClick={handleSend}
            disabled={isStreaming || !text.trim()}
            className='bg-blue-600 text-white px-4 py-2 rounded-lg font-semibold hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors'
          >
            Send
          </button>

          {onVoiceStart && (
            <button
              onClick={onVoiceStart}
              className={`px-4 py-2 rounded-lg font-semibold transition-colors ${
                isVoiceActive
                  ? 'bg-red-600 text-white hover:bg-red-700'
                  : 'bg-green-600 text-white hover:bg-green-700'
              }`}
            >
              {isVoiceActive ? 'Stop Voice' : 'Start Voice'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

