      className={`flex gap-3 mb-4 ${isUser ? 'justify-end' : 'justify-start'}`}
    >
      <div
        className={`max-w-[85%] rounded-lg px-4 py-2 ${
          isUser
            ? 'bg-blue-600 text-white'
            : 'bg-gray-200 text-gray-900'
        }`}
      >
        <div className='whitespace-pre-wrap break-words text-sm leading-relaxed'>
          {content}
        </div>
        {isAssistant && (
          <div className='flex gap-2 mt-2 pt-2 border-t border-gray-300'>
            <button
              onClick={handleCopy}
              className='text-xs px-2 py-1 hover:bg-gray-300 rounded'
              title='Copy message'
            >
              Copy
            </button>
          </div>
        )}
        {timestamp && (
          <div className={`text-xs mt-1 ${
            isUser ? 'text-blue-200' : 'text-gray-500'
          }`}>
            {new Date(timestamp).toLocaleTimeString()}
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useRef } from 'react';
import { OmegaMessage } from './OmegaMessage';
import type { OmegaMessage as MessageType } from '../../hooks/useOmegaChat';

interface ChatViewProps {
  messages: MessageType[];
  isStreaming: boolean;
  systemState: 'idle' | 'thinking' | 'followup' | 'error';
  error?: string | null;
}

export function ChatView({
  messages,
  isStreaming,
  systemState,
  error,
}: ChatViewProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (containerRef.current) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight;
    }
  }, [messages, isStreaming]);

  return (
    <div className='flex-1 overflow-y-auto p-4 bg-white'>
      {messages.length === 0 ? (
        <div className='flex items-center justify-center h-full'>
          <div className='text-center text-gray-500'>
            <p className='text-lg font-semibold mb-2'>Start a conversation</p>
            <p className='text-sm'>Send a message or use voice mode</p>
          </div>
        </div>
      ) : (
        <div ref={containerRef} className='space-y-4'>
          {messages.map((msg) => (
            <OmegaMessage
              key={msg.id}
              role={msg.role}
              content={msg.content}
              timestamp={msg.createdAt}
            />
          ))}

          {systemState === 'thinking' && (
            <div className='flex gap-2 items-center text-gray-600'>
              <div className='flex gap-1'>
                <div className='w-2 h-2 bg-gray-400 rounded-full animate-bounce' />
                <div className='w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-100' />
                <div className='w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-200' />
              </div>
              <span className='text-sm'>OmegA is thinking...</span>
            </div>
          )}

          {systemState === 'error' && error && (
            <div className='bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded'>
              <p className='text-sm font-semibold'>Error</p>
              <p className='text-sm'>{error}</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState } from 'react';

interface ChatComposerProps {
  onSendMessage: (text: string) => void;
  onVoiceStart?: () => void;
  isStreaming?: boolean;
  isVoiceActive?: boolean;
  heardText?: string;
}

export function ChatComposer({
  onSendMessage,
  onVoiceStart,
  isStreaming = false,
  isVoiceActive = false,
  heardText = '',
}: ChatComposerProps) {
  const [text, setText] = useState('');

  const handleSend = () => {
    if (text.trim()) {
      onSendMessage(text);
      setText('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className='border-t border-gray-200 bg-white p-4'>
      {heardText && (
        <div className='mb-2 text-sm italic text-gray-600'>
          <span className='font-semibold'>Heard:</span> {heardText}
        </div>
      )}

      <div className='flex gap-2'>
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder='Type a message... (Shift+Enter for newline)'
          disabled={isStreaming}
          className='flex-1 resize-none border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100'
          rows={3}
        />

        <div className='flex flex-col gap-2'>
          <button
            onClick={handleSend}
            disabled={isStreaming || !text.trim()}
            className='bg-blue-600 text-white px-4 py-2 rounded-lg font-semibold hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors'
          >
            Send
          </button>

          {onVoiceStart && (
            <button
              onClick={onVoiceStart}
              className={`px-4 py-2 rounded-lg font-semibold transition-colors ${
                isVoiceActive
                  ? 'bg-red-600 text-white hover:bg-red-700'
                  : 'bg-green-600 text-white hover:bg-green-700'
              }`}
            >
              {isVoiceActive ? 'Stop Voice' : 'Start Voice'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import type { OmegaSession } from '../../hooks/useOmegaChat';

interface ConversationSidebarProps {
  conversations: OmegaSession[];
  activeConvoId: string | null;
  onSelectConversation: (id: string) => void;
  onNewConversation: () => void;
  onDeleteConversation: (id: string) => void;
  isOpen?: boolean;
}

export function ConversationSidebar({
  conversations,
  activeConvoId,
  onSelectConversation,
  onNewConversation,
  onDeleteConversation,
  isOpen = true,
}: ConversationSidebarProps) {
  return (
    <aside
      className={`bg-gray-50 border-r border-gray-200 flex flex-col ${
        isOpen ? 'w-64' : 'w-0 overflow-hidden'
      } transition-all duration-200`}
    >
      <div className='p-4 border-b border-gray-200'>
        <button
          onClick={onNewConversation}
          className='w-full bg-blue-600 text-white px-4 py-2 rounded-lg font-semibold hover:bg-blue-700 transition-colors'
        >
          + New Chat
        </button>
      </div>

      <nav className='flex-1 overflow-y-auto p-2'>
        {conversations.map((convo) => (
          <div
            key={convo.id}
