'use client';

import React from 'react';
import type { VoiceState } from '../../hooks/useVoiceEngine';

interface VoiceModeProps {
  isActive: boolean;
  state: VoiceState;
  transcript: string;
  interimTranscript: string;
  onStop: () => void;
  onInterrupt?: () => void;
}

export function VoiceMode({
  isActive,
  state,
  transcript,
  interimTranscript,
  onStop,
  onInterrupt,
}: VoiceModeProps) {
  if (!isActive) return null;

  const getStateColor = () => {
    switch (state) {
      case 'listening':
        return 'border-blue-500 bg-blue-50';
      case 'thinking':
        return 'border-yellow-500 bg-yellow-50';
      case 'followup':
        return 'border-green-500 bg-green-50';
      case 'error':
        return 'border-red-500 bg-red-50';
      default:
        return 'border-gray-300 bg-gray-50';
    }
  };

  return (
    <div className='fixed inset-0 bg-black/50 flex items-center justify-center z-50'>
      <div
        className={`border-4 rounded-2xl p-8 max-w-md w-full mx-4 ${getStateColor()}`}
      >
        <div className='text-center mb-6'>
          <div className='inline-block mb-4'>
            <div className='w-16 h-16 rounded-full border-4 border-current flex items-center justify-center animate-pulse'>
              <svg
                width='32'
                height='32'
                viewBox='0 0 24 24'
                fill='currentColor'
              >
                <path d='M12 1c-6.338 0-12 4.226-12 10.007 0 2.05.738 4.063 2.047 5.625.055 3.215 1.308 4.953 4.953 5.368v-3h3v3h2v-3h3v3c3.645-.415 4.898-2.153 4.953-5.368 1.309-1.562 2.047-3.575 2.047-5.625 0-5.781-5.662-10.007-12-10.007z' />
              </svg>
            </div>
          </div>

          <h2 className='text-xl font-bold text-gray-900 mb-2'>Voice Mode</h2>
          <p className='text-sm font-semibold text-gray-700 capitalize'>
            {state === 'listening' && 'Listening...'}
            {state === 'thinking' && 'Processing...'}
            {state === 'followup' && 'Ready for follow-up'}
            {state === 'error' && 'Error detected'}
            {state === 'idle' && 'Standby'}
          </p>
        </div>

        {(transcript || interimTranscript) && (
          <div className='mb-6 p-3 bg-white rounded-lg border border-current'>
            <p className='text-sm text-gray-900'>
              {transcript}
              <span className='italic text-gray-500'>{interimTranscript}</span>
            </p>
          </div>
        )}

        <div className='flex gap-3'>
          {onInterrupt && (
            <button
              onClick={onInterrupt}
              className='flex-1 px-4 py-2 bg-white border-2 border-current rounded-lg font-semibold hover:bg-gray-100 transition-colors'
            >
              Interrupt
            </button>
          )}

          <button
            onClick={onStop}
            className='flex-1 px-4 py-2 bg-current text-white rounded-lg font-semibold hover:opacity-90 transition-opacity'
          >
            Stop
          </button>
        </div>
      </div>
    </div>
  );
}

