'use client';

import React, { useState } from 'react';
import type { VoiceSettings } from '../../hooks/useVoiceEngine';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  settings: VoiceSettings;
  onSettingsChange: (settings: Partial<VoiceSettings>) => void;
}

export function SettingsModal({
  isOpen,
  onClose,
  settings,
  onSettingsChange,
}: SettingsModalProps) {
  const [localSettings, setLocalSettings] = useState(settings);

  const handleSave = () => {
    onSettingsChange(localSettings);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className='fixed inset-0 bg-black/30 flex items-center justify-center z-50'>
      <div className='bg-white rounded-lg shadow-xl p-6 max-w-md w-full mx-4'>
        <h2 className='text-xl font-bold text-gray-900 mb-4'>Settings</h2>

        <div className='space-y-4 mb-6'>
          <div>
            <label className='block text-sm font-semibold text-gray-700 mb-2'>
              Language
            </label>
            <select
              value={localSettings.language}
              onChange={(e) =>
                setLocalSettings((prev) => ({
                  ...prev,
                  language: e.target.value,
                }))
              }
              className='w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500'
            >
              <option value='en-US'>English (US)</option>
              <option value='en-GB'>English (UK)</option>
              <option value='es-ES'>Spanish</option>
              <option value='fr-FR'>French</option>
              <option value='de-DE'>German</option>
            </select>
          </div>

          <div>
            <label className='block text-sm font-semibold text-gray-700 mb-2'>
              Volume: {Math.round(localSettings.volume * 100)}%
            </label>
            <input
              type='range'
              min='0'
              max='1'
              step='0.1'
              value={localSettings.volume}
              onChange={(e) =>
                setLocalSettings((prev) => ({
                  ...prev,
                  volume: parseFloat(e.target.value),
                }))
              }
              className='w-full'
            />
          </div>

          <div>
            <label className='flex items-center gap-2'>
              <input
                type='checkbox'
                checked={localSettings.interruptible}
                onChange={(e) =>
                  setLocalSettings((prev) => ({
                    ...prev,
                    interruptible: e.target.checked,
                  }))
                }
                className='w-4 h-4'
              />
              <span className='text-sm font-semibold text-gray-700'>
                Allow interruption
              </span>
            </label>
          </div>
        </div>

        <div className='flex gap-3'>
          <button
            onClick={onClose}
            className='flex-1 px-4 py-2 border border-gray-300 rounded-lg font-semibold text-gray-700 hover:bg-gray-50 transition-colors'
          >
            Cancel
          </button>
          <button
            onClick={handleSave}
            className='flex-1 px-4 py-2 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition-colors'
          >
            Save
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

import React from 'react';

interface Action {
  id: string;
  label: string;
  icon?: string;
  destructive?: boolean;
  onClick: () => void;
}

interface ActionSheetProps {
  isOpen: boolean;
  onClose: () => void;
  actions: Action[];
  title?: string;
}

export function ActionSheet({
  isOpen,
  onClose,
  actions,
  title,
}: ActionSheetProps) {
  if (!isOpen) return null;

  return (
    <div className='fixed inset-0 bg-black/30 flex items-end z-50'>
      <div className='bg-white rounded-t-2xl w-full max-h-96 overflow-y-auto'>
        {title && (
          <div className='sticky top-0 bg-white border-b border-gray-200 p-4'>
            <h3 className='font-semibold text-gray-900'>{title}</h3>
          </div>
        )}

        <div className='divide-y divide-gray-200'>
          {actions.map((action) => (
            <button
              key={action.id}
              onClick={() => {
                action.onClick();
                onClose();
              }}
              className={`w-full px-4 py-3 text-left text-sm font-semibold transition-colors ${
                action.destructive
                  ? 'text-red-600 hover:bg-red-50'
                  : 'text-blue-600 hover:bg-blue-50'
              }`}
            >
              {action.label}
            </button>
          ))}

          <button
            onClick={onClose}
            className='w-full px-4 py-3 text-left text-sm font-semibold text-gray-600 hover:bg-gray-50'
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
}
